module RefModule (
    input clk,
    input reset,
    input up_down,
    output [3:0] count );reg [3:0] unused_count_reg;

always @(posedge clk) begin
    if (reset)
        unused_count_reg <= 4'b0000;
    else if (up_down)
        unused_count_reg <= unused_count_reg + 1;
    else
        unused_count_reg <= unused_count_reg - 1;
end

assign count = unused_count_reg;

endmodule
